INSERT INTO formations (id_formation, titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) SELECT gen_random_uuid(), v.* FROM (VALUES ('Formation en télémarketing', 'Formation sur l’organisation administrative, financière et comptable conforme aux normes SYSCOHADA révisé.', 4, 150000.00, 'entreprise', '2026-09-05', 30, '2026-01-14 12:37:32', '2026-02-18 23:44:04', NULL, E'--- OBJECTIFS ---\n• Comprendre le cadre légal et les exigences du SYSCOHADA\n• Structurer efficacement les services administratifs, financiers et comptables\n• Mettre en place des processus conformes aux normes\n• Établir et analyser les états financiers\n• Optimiser la gestion et le pilotage de l’entreprise\n\n--- OBJECTIFS DÉTAILLÉS ---\nComprendre le cadre légal du SYSCOHADA révisé, structurer les services administratifs et financiers, mettre en place des processus conformes, établir et analyser les états financiers et optimiser la gestion selon les standards SYSCOHADA.\n\n--- PRÉREQUIS ---\nConnaissances de base en comptabilité ou gestion financière. Une expérience préalable en gestion d’entreprise est recommandée.\n\n--- CONTENU ---\nModule 1 : Introduction au SYSCOHADA révisé\nModule 2 : Organisation administrative et gestion documentaire\nModule 3 : Gestion financière et contrôle interne\nModule 4 : Comptabilité selon le SYSCOHADA révisé\nModule 5 : États financiers et analyse\nModule 6 : Optimisation et performance de l’organisation\n\n--- NIVEAU ---\nTous niveaux\n\n--- PUBLIC ---\nChefs d’entreprise, dirigeants, responsables administratifs et financiers, comptables, auditeurs internes, consultants en gestion financière et comptable.\n\n--- MÉTHODES ---\nApports théoriques interactifs, études de cas réels, ateliers pratiques sur logiciels comptables, simulations et supports pédagogiques.\n\n--- SUPPORTS ---\nGuides SYSCOHADA, logiciels comptables, tableurs Excel, modèles de documents, supports PDF et slides.\n\n--- CERTIFICATION ---\nAttestation de participation remise par ISD Groupe', 'ba52f30c-c061-41b8-b0f7-afa6eca6fa76')) AS v(titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) WHERE NOT EXISTS (SELECT 1 FROM formations f WHERE f.titre = v.titre AND f.date_debut = v.date_debut::date);
